UNPATCHED KsrPersistMemoryPartition (0x1C0008780):
  ObjectSecurity = ObOpenObjectByPointerWithTag(a2, 0x200u, nullptr, 1u, PsPartitionType, 0, 0x2072734Bu, &Handle);
  ObQueryNameString(a2, ...); ObGetObjectSecurity(a2, ...);
  KsrpQueryMemoryRuns((__int64)a2, &P, &v33); KsrpQueryIoSpaceRuns((__int64)a2, &v36, &v34);
  v40[3] = a2; v40[9] = Handle;                 // raw object + handle handed to external routine
  ObjectSecurity = ((...)KsrpPersistMemoryPartitionRoutinePointer)(v40);
  if (ObjectSecurity < 0 && Handle) ZwClose(Handle);   // no driver-held reference exists

PATCHED KsrPersistMemoryPartition (0x14000A820):
  ObReferenceObjectByHandle(Handle, 2u, PsPartitionType, 0, &Object, nullptr); v8 = Object;
  // ObQueryNameString(v8,...), ObGetObjectSecurity(v8,...), KsrpQueryMemoryRuns(v8,...), KsrpQueryIoSpaceRuns(v8,...)
  v39[3] = 0; v39[9] = 0;                        // object/handle no longer passed to external routine
  ((...)KsrpPersistMemoryPartitionRoutinePointer[0])(v39);
  KsrpAddPartitionToList(Handle, v8, v34);        // inline insertion; on success Handle=0, v8=0
  if (v8) ObfDereferenceObjectWithTag(v8, 0x2072734Bu);

KsrpDestoryPartitionList (unpatched 0x1C000BF68) already derefs [entry+0x10] (ObfDereferenceObject) and closes [entry+0x18] (ZwClose), confirming list entries are designed to own a reference and handle in both builds.
